PVOID
ExAllocatePoolWithTagHook(
    POOL_TYPE PoolType,
    SIZE_T    NumberOfBytes,
    ULONG     Tag)
{
    LogInfo("ExAllocatePoolWithTag Called with : Tag = 0x%x, Number Of Bytes = 0x%x, Pool Type = 0x%x ",
            Tag,
            NumberOfBytes,
            PoolType);

    return ExAllocatePoolWithTagOrig(PoolType, NumberOfBytes, Tag);
}
